646→    /// For OpenRouter Anthropic models, inject `cache_control` breakpoints
647→    /// on the system message and the last user message to enable prompt
648→    /// caching passthrough to Anthropic.
649→    fn apply_openrouter_cache_control(&self, messages: &mut [serde_json::Value]) {
650→        if !self.is_openrouter_anthropic()
651→            || matches!(self.cache_retention, moltis_config::CacheRetention::None)
652→        {
653→            return;
654→        }
655→
656→        let cache_control = serde_json::json!({ "type": "ephemeral" });
657→
658→        // Add cache_control to the system message content.
659→        for msg in messages.iter_mut() {
660→            if msg.get("role").and_then(serde_json::Value::as_str) != Some("system") {
661→                continue;
662→            }
663→            match msg.get_mut("content") {
664→                Some(content) if content.is_string() => {
665→                    let text = content.as_str().unwrap_or_default().to_string();
666→                    msg["content"] = serde_json::json!([{
667→                        "type": "text",
668→                        "text": text,
669→                        "cache_control": cache_control
670→                    }]);
671→                },
672→                Some(content) if content.is_array() => {
673→                    if let Some(last) = content.as_array_mut().and_then(|a| a.last_mut()) {
674→                        last["cache_control"] = cache_control.clone();
675→                    }
676→                },
677→                _ => {},
678→            }
679→            break;
680→        }
681→
682→        // Add cache_control to the last user message.
683→        if let Some(last_user) = messages
684→            .iter_mut()
685→            .rev()
686→            .find(|m| m.get("role").and_then(serde_json::Value::as_str) == Some("user"))
687→        {
688→            match last_user.get_mut("content") {
689→                Some(content) if content.is_string() => {
690→                    let text = content.as_str().unwrap_or_default().to_string();
691→                    last_user["content"] = serde_json::json!([{
692→                        "type": "text",
693→                        "text": text,
694→                        "cache_control": cache_control
695→                    }]);
696→                },
697→                Some(content) if content.is_array() => {
698→                    if let Some(last) = content.as_array_mut().and_then(|a| a.last_mut()) {
699→                        last["cache_control"] = cache_control;
700→                    }
701→                },
702→                _ => {},
703→            }
704→        }
705→    }
